<script setup lang="ts">import{useI18n}from'vue-i18n';import type{SubtitleConfig}from'@/types/subtitles';const model=defineModel<SubtitleConfig>({required:true});defineProps<{fonts:string[];fontsBusy:boolean}>();defineEmits<{refreshFonts:[]}>();const{t}=useI18n()</script>
<template><section class="form-section"><header class="section-heading"><h2>{{t('subtitles.typography.title')}}</h2><button class="refresh-button" :disabled="fontsBusy" @click="$emit('refreshFonts')">{{t('subtitles.typography.refreshFonts')}}</button></header><div class="form-grid"><label>{{t('subtitles.typography.font')}}<input v-model="model.fontFamily" list="subtitle-fonts" maxlength="128"><datalist id="subtitle-fonts"><option v-for="font in fonts" :key="font" :value="font" /></datalist></label><label>{{t('subtitles.typography.size')}}<input v-model.number="model.fontSize" type="number" min="12" max="72"></label><label>{{t('subtitles.typography.align')}}<select v-model="model.textAlign"><option value="left">{{t('subtitles.typography.left')}}</option><option value="center">{{t('subtitles.typography.center')}}</option><option value="right">{{t('subtitles.typography.right')}}</option></select></label></div></section></template>
